type Nullable<T> = { [K in keyof T]: T[K] | null };
type Optional<T> = { [K in keyof T]?: T[K] };
type Stringify<T>= { [K in keyof T]: string };

interface User { id: number; name: string; email: string; plan: string }

type NullableUser  = Nullable<User>;
type OptionalUser  = Optional<User>;
type StringUser    = Stringify<User>;

const nullUser: NullableUser = { id: null, name: null, email: null, plan: null };
const partUser: OptionalUser = { name: "Alice" };
const strUser: StringUser   = { id: "1", name: "Bob", email: "b@co.com", plan: "pro" };

console.log(`Nullable: ${JSON.stringify(nullUser)}`);
console.log(`Optional: ${JSON.stringify(partUser)}`);
console.log(`Stringified id: ${strUser.id} (${typeof strUser.id})`);

type IsArray<T> = T extends unknown[] ? true : false;
type ElementOf<T> = T extends (infer E)[] ? E : never;
type NonNullable2<T> = T extends null | undefined ? never : T;

type A = IsArray<number[]>;    // true
type B = IsArray<string>;      // false
type C = ElementOf<Date[]>;    // Date
type D = ElementOf<string>;    // never (not array)
type E = NonNullable2<string | null | undefined>;  // string

// Runtime demo
function getFirstElement<T>(arr: T[]): ElementOf<T[]> | undefined {
  return arr[0] as ElementOf<T[]> | undefined;
}

console.log(getFirstElement([1, 2, 3]));
console.log(getFirstElement(["a", "b", "c"]));
console.log(String(getFirstElement([])));

type Method  = "GET" | "POST" | "PUT" | "DELETE";
type Version = "v1" | "v2";
type Resource= "users" | "orders" | "products";

// Generates all valid route strings
