}

type ReturnType2<T> = T extends (...args: unknown[]) => infer R ? R : never;
type FirstParam<T>  = T extends (first: infer P, ...rest: unknown[]) => unknown ? P : never;
type PromiseValue<T>= T extends Promise<infer V> ? V : T;

async function fetchUser(): Promise<{ id: number; name: string }> {
  return { id: 1, name: "Alice" };
}

type UserResult    = ReturnType2<typeof fetchUser>;   // Promise<{ id, name }>
type FetchedUser   = PromiseValue<UserResult>;         // { id, name }

function greet(name: string, age: number): string {
  return `Hello ${name}, age ${age}`;
}

type GreetReturn = ReturnType2<typeof greet>;  // string
type GreetFirst  = FirstParam<typeof greet>;   // string

console.log(`greet returns: ${typeof "" === "string" ? "string" : "other"}`);
console.log(greet("Alice", 30));

type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonValue[]
  | { [key: string]: JsonValue };

type TreeNode<T> = {
  value: T;
  children: TreeNode<T>[];
};

const settings: JsonValue = {
  name: "uByte",
  version: 3,
  features: { typescript: true, sql: true },
  supported: ["go", "python", "typescript"],
};

const tree: TreeNode<string> = {
  value: "root",
  children: [
    { value: "child1", children: [{ value: "grandchild", children: [] }] },
    { value: "child2", children: [] },
  ],
};

function countNodes<T>(node: TreeNode<T>): number {
  return 1 + node.children.reduce((s, c) => s + countNodes(c), 0);
}

console.log(`JSON valid: ${typeof settings === "object"}`);
console.log(`Tree nodes: ${countNodes(tree)}`);

// Distributive: applied to each union member separately
type ToArray<T> = T extends unknown ? T[] : never;

type A = ToArray<string | number>;   // string[] | number[]
// Not: (string | number)[]

// To prevent distribution, wrap in a tuple:
type ToArrayND<T> = [T] extends [unknown] ? T[] : never;
type B = ToArrayND<string | number>;  // (string | number)[]

// Practical use: filter union members
type NonNullableUnion<T> = T extends null | undefined ? never : T;
type C = NonNullableUnion<string | null | number | undefined>;  // string | number

const strArr: ToArray<string> = ["a", "b", "c"];
const numArr: ToArray<number> = [1, 2, 3];

console.log(`String array: ${strArr.join(", ")}`);
console.log(`Number array: ${numArr.join(", ")}`);
console.log(`Type filtering works at compile time`);

type Concat<T extends unknown[], U extends unknown[]> = [...T, ...U];
type Head<T extends unknown[]> = T extends [infer H, ...unknown[]] ? H : never;
type Tail<T extends unknown[]> = T extends [unknown, ...infer T] ? T : never;

function concat<T extends unknown[], U extends unknown[]>(a: T, b: U): Concat<T, U> {
  return [...a, ...b] as Concat<T, U>;
}

const a = [1, 2, 3] as const;
const b = ["x", "y"] as const;
const combined = concat(a, b);

console.log(`Combined: ${combined.join(", ")}`);
console.log(`Length: ${combined.length}`);
console.log(`Type check: ${typeof combined[0]} and ${typeof combined[3]}`);

type Brand<T, B extends string> = T & { readonly _brand: B };

type UserId    = Brand<number, "UserId">;
type OrderId   = Brand<number, "OrderId">;
type ProductId = Brand<number, "ProductId">;

const toUserId    = (n: number): UserId    => n as UserId;
const toOrderId   = (n: number): OrderId   => n as OrderId;
const toProductId = (n: number): ProductId => n as ProductId;

function getUser(id: UserId): string    { return `User#${id}`; }
function getOrder(id: OrderId): string  { return `Order#${id}`; }

const uid = toUserId(42);
const oid = toOrderId(100);

console.log(getUser(uid));
console.log(getOrder(oid));
// getUser(oid);  // ← TypeScript error: OrderId is not UserId
console.log(`uid + oid = ${uid + oid}`);  // Both are numbers at runtime

type Timestamped = { createdAt: string; updatedAt: string };
type SoftDeletable = { deletedAt: string | null; isDeleted: boolean };
type Identifiable<T> = { id: T };

type Entity<TId = number> = Identifiable<TId> & Timestamped & SoftDeletable;

interface UserFields { name: string; email: string; role: string }
type User = Entity<number> & UserFields;

function createEntity<T>(fields: T): Entity & T {
  return {
    id: Math.floor(Math.random() * 1000),
    createdAt: "2024-01-15",
    updatedAt: "2024-01-15",
    deletedAt: null,
    isDeleted: false,
    ...fields,
  } as Entity & T;
}

const user = createEntity<UserFields>({ name: "Alice", email: "alice@co.com", role: "admin" });
console.log(`${user.name} — created: ${user.createdAt}`);
console.log(`Deleted: ${user.isDeleted}`);

type Getter<T extends string> = `get${Capitalize<T>}`;
type Setter<T extends string> = `set${Capitalize<T>}`;

type PropertyAccessors<T extends string> = {
  [K in T as Getter<K>]: () => string;
} & {
  [K in T as Setter<K>]: (value: string) => void;
};

type UserAccessors = PropertyAccessors<"name" | "email" | "role">;

// Implement all generated methods
const userObj: UserAccessors = {
  getName:  () => "Alice",
  setName:  (v) => { console.log(`Setting name to ${v}`); },
  getEmail: () => "alice@co.com",
  setEmail: (v) => { console.log(`Setting email to ${v}`); },
  getRole:  () => "admin",
  setRole:  (v) => { console.log(`Setting role to ${v}`); },
};

console.log(userObj.getName());
console.log(userObj.getEmail());
userObj.setRole("editor");

type Animal = { name: string; sound(): string };
type Dog    = { name: string; sound(): string; breed: string };

// Covariance: Dog is assignable to Animal (Dog extends Animal)
const dog: Dog = { name: "Rex", breed: "Lab", sound: () => "Woof" };
const animal: Animal = dog;  // ✓ Dog is more specific than Animal

// Function return types are covariant
type GetAnimal = () => Animal;
type GetDog    = () => Dog;
const getDog: GetDog = () => dog;
const getAnimal: GetAnimal = getDog;  // ✓ returning Dog satisfies Animal

// Function parameter types are contravariant
type HandleAnimal = (a: Animal) => void;
type HandleDog    = (d: Dog) => void;

const handleAnimal: HandleAnimal = (a) => console.log(`Animal: ${a.name}`);
// const handleDog: HandleDog = handleAnimal;  // TypeScript is bivariant for methods
// but contravariant for function types in strict mode

const result = getAnimal();
console.log(`Name: ${result.name}`);
console.log(`Sound: ${result.sound()}`);

type DeepReadonly<T> = T extends (infer E)[]
  ? ReadonlyArray<DeepReadonly<E>>
  : T extends object
  ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
  : T;

